function ProductCard({ product, addToCart }) {
    return (
      <div style={styles.card}>

        <img
          src={product.image}
          alt={product.name}
          style={styles.image}
        />

        <h3 style={styles.title}>{product.name}</h3>
        <p style={styles.price}>${product.price}</p>

        <button
          onClick={() => addToCart(product)}
          style={styles.button}
        >
          Add to Cart
        </button>

      </div>
    );
  }

  const styles = {
    card: {
      border: "1px solid #eee",
      borderRadius: "10px",
      width: "220px",
      padding: "12px",
      background: "white",
      textAlign: "center",
      boxShadow: "0 2px 6px rgba(0,0,0,0.1)"
    },

    image: {
      width: "100%",
      height: "150px",
      objectFit: "cover",
      borderRadius: "8px",
      marginBottom: "10px"
    },

    title: {
      margin: "5px 0"
    },

    price: {
      margin: "5px 0",
      fontWeight: "bold"
    },

    button: {
      marginTop: "8px",
      padding: "8px",
      background: "#007bff",
      color: "white",
      border: "none",
      borderRadius: "5px",
      cursor: "pointer"
    }
  };

  export default ProductCard;
